import java.util.Scanner;
import java.nio.CharBuffer;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Creating a CharBuffer with fixed size
        CharBuffer buffer = CharBuffer.allocate(10);

        // Copying user input into the fixed size buffer
        buffer.put(input, 0, Math.min(input.length(), buffer.remaining()));

        // Reset position to read from the beginning of the buffer
        buffer.rewind();

        System.out.println("Buffer content: " + new String(buffer.array()));
    }
}

